def greatest_common_divisor(a: int, b: int) -> int:
    """ Return a greatest common divisor of two integers a and b """
    if not isinstance(a, int) or not isinstance(b, int):
        raise ValueError("Both inputs must be integers")

    while b != 0:
        a, b = b, a % b
    return abs(a)

