    >>> largest_prime_factor(2048)
    2
    """
    def is_prime(k):
        if k < 2:
            return False
        for i in range(2, int(k**0.5) + 1):
            if k % i == 0:
                return False
        return True

    largest = 1
    # Check for the smallest prime factor (2)
    while n % 2 == 0:
        largest = max(largest, 2)
        n //= 2

    # Only check odd numbers from now on
    j = 3
