    compare_one(1, 2.5) ➞ 2.5
    compare_one(1, "2,3") ➞ "2,3"
    compare_one("5,1", "6") ➞ "6"
    compare_one("1", 1) ➞ None
    """
    def convert_to_float(value):
        if isinstance(value, str):
            value = value.replace(',', '.')
        return float(value)

    temp_a, temp_b = a, b
    val_a = convert_to_float(temp_a)
    val_b = convert_to_float(temp_b)

    if val_a == val_b:
        return None

    if isinstance(a, str):
        return a if val_a > val_b else b
    elif isinstance(b, str):
        return b if val_b > val_a else a
    else:
        return a if val_a > val_b else b

